class Solution {
    public boolean reorderedPowerOf2(int n) {
        String s = String.valueOf(n);
        for (int i = 0; i <= 30; i++) {
            if (is reordered(String.valueOf(1 << i)) && hasSameDigits(s, String.valueOf(1 << i))) {
                return true;
            }
        }
        return false;
    }
    private boolean hasSameDigits(String s1, String s2) {
        if (s1.length() != s2.length()) {
            return false;
        }
        int[] count = new int[10];
        for (char c : s1.toCharArray()) {
            count[c - '0']++;
        }
        for (char c : s2.toCharArray()) {
            count[c - '0']--;
            if (count[c - '0'] < 0) {
                return false;
            }
        }
        return true;
    }
    private boolean is reordered(String s) {
        if (s.length() == 0) {
            return false;
        }
        int num = Integer.parseInt(s);
        return (num & (num - 1)) == 0;
    }
}
